return {
  draw: function(ctx, W, H, t, dt) {
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    ctx.strokeStyle = '#374151';
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.moveTo(80, H / 2);
    ctx.lineTo(W - 40, H / 2);
    ctx.stroke();

    var numPoints = 5;
    var spacing = (W - 120) / (numPoints - 1);
    for (var i = 0; i < numPoints; i++) {
      var val = i;
      var x = 80 + i * spacing;
      var y = H / 2;

      var activeIdx = Math.floor(t * 0.03) % numPoints;
      var isActive = (i === activeIdx);

      if (val === 0) {
        ctx.strokeStyle = isActive ? '#EC4899' : '#6B7280';
        ctx.lineWidth = isActive ? 5 : 3;
        ctx.beginPath();
        ctx.arc(x, y, isActive ? 18 + Math.sin(t * 0.15) * 3 : 12, 0, Math.PI * 2);
        ctx.stroke();

        ctx.fillStyle = isActive ? '#EC4899' : '#9CA3AF';
        ctx.font = 'bold 16px -apple-system, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText('0 (Origin)', x, y - 25);
      } else {
        var r = isActive ? 14 + Math.sin(t * 0.15) * 3 : 8;
        ctx.fillStyle = isActive ? '#8B5CF6' : '#4B5563';
        ctx.beginPath();
        ctx.arc(x, y, r, 0, Math.PI * 2);
        ctx.fill();

        ctx.font = 'bold 16px -apple-system, sans-serif';
        ctx.fillStyle = isActive ? '#F3F4F6' : '#9CA3AF';
        ctx.textAlign = 'center';
        ctx.fillText(val.toString(), x, y - 25);
      }
    }
  }
};
